### Testing with TestBed

`TestBed` is the primary API for configuring and creating Angular testing modules:

```typescript
import { TestBed, ComponentFixture } from '@angular/core/testing';
import { UserComponent } from './user.component';

describe('UserComponent', () => {
  let component: UserComponent;
  let fixture: ComponentFixture<UserComponent>;

  beforeEach(async () => {
    await TestBed.configureTestingModule({
      imports: [UserComponent]
    }).compileComponents();

    fixture = TestBed.createComponent(UserComponent);
    component = fixture.componentInstance;
  });

  it('should create', () => {
    expect(component).toBeTruthy();
  });
});
```

### Component with Input/Output Testing

```typescript
@Component({
  standalone: true,
  template: `
    <p>{{ name }}</p>
    <button (click)="handleClick()">Click</button>
  `
})
export class GreetingComponent {
  @Input() name: string = '';
  @Output() clicked = new EventEmitter<string>();

  handleClick() {
    this.clicked.emit(this.name);
  }
}

describe('GreetingComponent', () => {
  it('should display name', () => {
    const fixture = TestBed.createComponent(GreetingComponent);
    fixture.componentRef.setInput('name', 'John');
    fixture.detectChanges();

    const el = fixture.nativeElement as HTMLElement;
    expect(el.querySelector('p')?.textContent).toBe('John');
  });

  it('should emit click event', () => {
    const fixture = TestBed.createComponent(GreetingComponent);
    fixture.componentRef.setInput('name', 'John');
    fixture.detectChanges();

    spyOn(fixture.componentInstance.clicked, 'emit');
    fixture.nativeElement.querySelector('button')?.click();

    expect(fixture.componentInstance.clicked.emit).toHaveBeenCalledWith('John');
  });
});
```

### Service Testing with HttpClientTestingController

```typescript
import { TestBed } from '@angular/core/testing';
import { HttpClientTestingModule, HttpTestingController } from '@angular/common/http/testing';
import { UserService } from './user.service';

describe('UserService', () => {
  let service: UserService;
  let httpMock: HttpTestingController;

  beforeEach(() => {
    TestBed.configureTestingModule({
      imports: [HttpClientTestingModule],
      providers: [UserService]
    });
    service = TestBed.inject(UserService);
    httpMock = TestBed.inject(HttpTestingController);
  });

  afterEach(() => {
    httpMock.verify(); // Ensure no outstanding requests
  });

  it('should fetch users', () => {
    const mockUsers = [{ id: 1, name: 'John' }];

    service.getUsers().subscribe(users => {
      expect(users).toEqual(mockUsers);
    });

    const req = httpMock.expectOne('/api/users');
    expect(req.request.method).toBe('GET');
    req.flush(mockUsers);
  });

  it('should handle error', () => {
    service.getUsers().subscribe({
      error: (err) => expect(err.message).toContain('500')
    });

    const req = httpMock.expectOne('/api/users');
    req.flush('Server error', { status: 500, statusText: 'Server Error' });
  });
});
```

### DetectChanges

`fixture.detectChanges()` runs change detection to update the DOM. Call it **after** setting properties or responding to async events:

```typescript
it('should update view when input changes', () => {
  component.name = 'Alice';
  fixture.detectChanges(); // Apply the change
  expect(fixture.nativeElement.textContent).toContain('Alice');
});
```

